#!/usr/bin/env python3
"""CODEVERT G0 runner — extraction + full-census kappa_q^indep + resources.

MEASURED outputs (results/g0-metrics.json):
  - kappa_q^indep per family x repo over the FULL frozen census (population
    value on the pinned pool — no sampling error on the pool itself);
  - repo-cluster bootstrap CI (n=6 clusters, 10k resamples, seed-pinned) for
    the pooled figures — the honest generalization uncertainty; wide by
    construction and disclosed as such;
  - unknown-edge mass by construct family (reason code), share unrestricted;
  - identifier-collision / candidate-set-growth stats;
  - resource facts: extraction wall time, peak RSS, SQLite packed store
    bytes, bytes/edge, per-family query latency p50/p95 (this Python
    reference engine, pinned 2-core rig, nice -n 10).
Statuses: proved counts toward kappa; unknown_incomplete / target_not_found
do not. proved-EMPTY negatives count as proved (valid negative answers).
"""
import json, os, random, resource, sqlite3, sys, time

sys.setrecursionlimit(100000)
from extractor import Extractor
from engine import World, run_query

BASE = os.path.dirname(os.path.abspath(__file__))
BOOT_SEED = 20260711
FAMILIES = ["callees_of", "imports_of", "contains", "contained_in",
            "callers_of", "imported_by", "where_defined", "instance_of"]
FORWARD = set(FAMILIES[:4])


def rss_mb():
    return resource.getrusage(resource.RUSAGE_SELF).ru_maxrss / 1024.0


def store_sqlite(path, edges):
    if os.path.exists(path):
        os.remove(path)
    con = sqlite3.connect(path)
    con.execute("CREATE TABLE edges (rel TEXT, src TEXT, dst TEXT, status TEXT,"
                " cand TEXT, file TEXT, span_a INT, span_b INT, reason TEXT)")
    con.executemany("INSERT INTO edges VALUES (?,?,?,?,?,?,?,?,?)",
                    [e.row() for e in edges])
    con.execute("CREATE INDEX ix_dst ON edges(rel, dst)")
    con.execute("CREATE INDEX ix_src ON edges(rel, src)")
    con.commit()
    con.execute("VACUUM")
    con.close()
    return os.path.getsize(path)


def main():
    exclude_tests = os.environ.get("G0_EXCLUDE_TESTS") == "1"
    census = json.load(open(os.path.join(BASE, "results", "census.json")))
    out = {"repos": {}, "pooled": {}}
    per_repo_family = {}       # repo -> family -> (proved, total)
    lat = {f: [] for f in FAMILIES}
    all_unknown = {}
    unrestricted = {"call": 0, "import": 0, "binding": 0, "instantiate": 0}
    unknown_by_rel = {"call": 0, "import": 0, "binding": 0, "instantiate": 0}
    cand_growth = []           # (repo, cand_name, n_defs_with_that_name)
    tot_edges = tot_proved = tot_unknown = 0
    tot_store = 0

    for repo, cdata in sorted(census["repos"].items()):
        root = os.path.join(BASE, "corpus", repo)
        t0 = time.time()
        ex = Extractor(root, repo)
        edges = ex.extract()
        t_extract = time.time() - t0
        world = World(edges, ex.modules)
        store_bytes = store_sqlite(os.path.join(BASE, "results",
                                                repo + ".sqlite"), edges)
        tot_store += store_bytes

        # --- edge stats ---
        n_p = sum(1 for e in edges if e.status == "proved")
        n_u = len(edges) - n_p
        tot_edges += len(edges)
        tot_proved += n_p
        tot_unknown += n_u
        reasons = {}
        for e in edges:
            if e.status == "unknown":
                reasons[e.reason] = reasons.get(e.reason, 0) + 1
                all_unknown[e.reason] = all_unknown.get(e.reason, 0) + 1
                if e.rel in unknown_by_rel:
                    unknown_by_rel[e.rel] += 1
                    if e.cand == "*":
                        unrestricted[e.rel] += 1

        # --- candidate-set growth: for unknown call candidates, how many
        # same-named defs exist in the repo (ambiguity-set pressure) ---
        name_def_count = {}
        for mi in ex.modules.values():
            for qual in mi.defs:
                nm = qual.split(".")[-1]
                name_def_count[nm] = name_def_count.get(nm, 0) + 1
        seen_c = {}
        for e in edges:
            if e.status == "unknown" and e.rel == "call" and e.cand and e.cand != "*":
                seen_c[e.cand] = name_def_count.get(e.cand, 0)
        for c, n in seen_c.items():
            cand_growth.append((repo, c, n))

        # --- full-census kappa per family + latency ---
        fam_stats = {}
        from extractor import _is_test_path
        for fam in FAMILIES:
            u = cdata["universes"][fam]
            if exclude_tests:
                u = [t for t in u if "file" not in t or not _is_test_path(t["file"])]
                if fam == "where_defined":
                    u = []  # name-keyed; not file-stratifiable, disclosed
            proved = 0
            statuses = {"proved": 0, "unknown_incomplete": 0,
                        "target_not_found": 0, "proved_empty": 0}
            t_fam = []
            for tgt in u:
                q0 = time.perf_counter()
                st, listing, blocking = run_query(world, fam, tgt)
                t_fam.append(time.perf_counter() - q0)
                if st == "proved":
                    proved += 1
                    statuses["proved"] += 1
                    if not listing:
                        statuses["proved_empty"] += 1
                else:
                    statuses[st] += 1
            fam_stats[fam] = {"n": len(u), "proved": proved,
                              "kappa": proved / len(u) if u else None,
                              "statuses": statuses}
            if not u:
                fam_stats[fam]["kappa"] = 0.0  # placeholder; excluded from macro below
            lat[fam].extend(t_fam)
        per_repo_family[repo] = {f: (fam_stats[f]["proved"], fam_stats[f]["n"])
                                 for f in FAMILIES}
        out["repos"][repo] = {
            "extract_wall_s": round(t_extract, 3),
            "n_modules": len(ex.modules),
            "n_parsed": sum(1 for m in ex.modules.values() if m.parsed),
            "edges_total": len(edges), "edges_proved": n_p, "edges_unknown": n_u,
            "unknown_reasons": dict(sorted(reasons.items(), key=lambda kv: -kv[1])),
            "sqlite_bytes": store_bytes,
            "bytes_per_edge": round(store_bytes / len(edges), 1) if edges else None,
            "exec_tainted_modules": [m.rel for m in ex.modules.values()
                                     if m.parsed and m.exec_taint],
            "star_import_modules": [m.rel for m in ex.modules.values()
                                    if m.parsed and m.star_import],
            "families": fam_stats,
            "extractor_stats": dict(ex.stats),
        }
        print(repo, "edges=%d (proved %d / unknown %d) store=%dB" %
              (len(edges), n_p, n_u, store_bytes),
              {f: round(fam_stats[f]["kappa"], 3) for f in FAMILIES}, flush=True)

    # ---------- pooled kappa ----------
    def pooled(repos):
        agg_q = [0, 0]          # query-pooled
        fam_p = {f: [0, 0] for f in FAMILIES}
        for r in repos:
            for f in FAMILIES:
                p, n = per_repo_family[r][f]
                agg_q[0] += p
                agg_q[1] += n
                fam_p[f][0] += p
                fam_p[f][1] += n
        nfam = sum(1 for f in FAMILIES if fam_p[f][1])
        macro = sum((fam_p[f][0] / fam_p[f][1]) for f in FAMILIES
                    if fam_p[f][1]) / nfam
        return agg_q[0] / agg_q[1], macro, {f: (fam_p[f][0] / fam_p[f][1])
                                            for f in FAMILIES if fam_p[f][1]}

    repos = sorted(per_repo_family)
    k_query, k_macro, k_fam = pooled(repos)

    rng = random.Random(BOOT_SEED)
    boots_q, boots_m = [], []
    for _ in range(10000):
        sample = [repos[rng.randrange(len(repos))] for _ in repos]
        q, m, _ = pooled(sample)
        boots_q.append(q)
        boots_m.append(m)
    boots_q.sort()
    boots_m.sort()

    def ci(v):
        return [round(v[int(0.025 * len(v))], 4), round(v[int(0.975 * len(v)) - 1], 4)]

    out["pooled"] = {
        "kappa_q_indep_query_pooled": round(k_query, 4),
        "kappa_q_indep_query_pooled_ci95_repo_cluster_bootstrap": ci(boots_q),
        "kappa_q_indep_family_macro": round(k_macro, 4),
        "kappa_q_indep_family_macro_ci95_repo_cluster_bootstrap": ci(boots_m),
        "kappa_by_family_pooled": {f: round(v, 4) for f, v in k_fam.items()},
        "kappa_forward_families_pooled": round(
            sum(k_fam.get(f, 0) for f in FAMILIES if f in FORWARD)
            / max(1, sum(1 for f in FORWARD if f in k_fam)), 4),
        "kappa_inverse_families_pooled": round(
            sum(k_fam.get(f, 0) for f in FAMILIES if f not in FORWARD)
            / max(1, sum(1 for f in FAMILIES if f not in FORWARD and f in k_fam)), 4),
        "n_census_queries_total": sum(n for r in repos
                                      for _, n in per_repo_family[r].values()),
        "bootstrap": {"seed": BOOT_SEED, "resamples": 10000, "clusters": len(repos),
                      "note": "repo-level cluster bootstrap; n=6 clusters -> wide CI, honest"},
        "edges": {"total": tot_edges, "proved": tot_proved, "unknown": tot_unknown,
                  "disproved": 0, "conflict": 0,
                  "unknown_share": round(tot_unknown / tot_edges, 4)},
        "unknown_by_reason": dict(sorted(all_unknown.items(), key=lambda kv: -kv[1])),
        "unknown_by_relation": unknown_by_rel,
        "unrestricted_unknowns_by_relation": unrestricted,
        "store_bytes_total": tot_store,
        "bytes_per_edge_pooled": round(tot_store / tot_edges, 1),
    }

    # candidate-set growth summary
    grow = sorted((n for _, _, n in cand_growth), reverse=True)
    n_multi = sum(1 for n in grow if n > 1)
    out["candidate_set_growth"] = {
        "n_distinct_unknown_call_candidates": len(grow),
        "share_matching_ge1_repo_def": round(
            sum(1 for n in grow if n >= 1) / len(grow), 4) if grow else None,
        "share_matching_ge2_repo_defs": round(n_multi / len(grow), 4) if grow else None,
        "max_same_name_defs": grow[0] if grow else 0,
        "top10": sorted(cand_growth, key=lambda x: -x[2])[:10],
    }

    # latency percentiles (population census reruns)
    lat_out = {}
    for f in FAMILIES:
        v = sorted(lat[f])
        if v:
            lat_out[f] = {"n": len(v),
                          "p50_us": round(v[len(v) // 2] * 1e6, 1),
                          "p95_us": round(v[int(len(v) * 0.95)] * 1e6, 1),
                          "max_ms": round(v[-1] * 1e3, 3)}
    out["latency_python_reference_engine"] = lat_out
    out["peak_rss_mb"] = round(rss_mb(), 1)
    out["rig"] = {"host": "2 shared vCPU EC2 (programme pinned box)",
                  "nice": 10, "python": sys.version.split()[0],
                  "note": "latency is for THIS Python dict-index reference engine, not the measured 5.29-7.82us compiled a5 engine; comparable only to itself"}

    outname = "g0-metrics-srconly.json" if exclude_tests else "g0-metrics.json"
    with open(os.path.join(BASE, "results", outname), "w") as fh:
        json.dump(out, fh, indent=1, sort_keys=True)
    print(json.dumps(out["pooled"], indent=1))
    print("peak RSS MB:", out["peak_rss_mb"])


if __name__ == "__main__":
    main()
#!/usr/bin/env python3
"""CODEVERT G0 — PY-STAT/1 extractor (enumerated static subset, fail-closed).

Implements the construct inventory in inventory.json (content-hashed) per
docs/next/design/CODEVERT.md §2.2 [PROPOSED-ASM: ASM-1031]. ast + symtable
only; pinned import resolver; 4-state facts (v0 emits proved/unknown only);
byte-span provenance; candidate-name sets on unknown edges ('*' =
unrestricted). Everything outside the inventory emits unknown fail-closed.
"""
import ast, builtins, os, symtable, sys

BUILTIN_NAMES = set(dir(builtins))


def _is_test_path(rel):
    p = "/" + rel.replace(os.sep, "/")
    base = os.path.basename(rel)
    return (any(m in p for m in ("/test/", "/tests/", "/docs/"))
            or base.startswith("test_") or base.endswith("_test.py")
            or base in ("conftest.py", "setup.py"))
EXEC_NAMES = {"exec", "eval", "compile"}
DYN_IMPORT_NAMES = {"__import__"}
ATTR_HOOKS = {"__getattr__", "__getattribute__", "__setattr__",
              "__init_subclass__", "__new__"}
ALLOWLIST = {"staticmethod", "classmethod", "abstractmethod",
             "abc.abstractmethod", "functools.wraps", "functools.lru_cache",
             "functools.cache", "typing.final", "final"}


class Edge:
    __slots__ = ("rel", "src", "dst", "status", "cand", "file", "span", "reason")

    def __init__(self, rel, src, dst, status, cand, file, span, reason):
        self.rel, self.src, self.dst = rel, src, dst
        self.status, self.cand = status, cand
        self.file, self.span, self.reason = file, span, reason

    def row(self):
        return (self.rel, self.src, self.dst, self.status, self.cand,
                self.file, self.span[0], self.span[1], self.reason)


def bind_names(t):
    """Simple-name assignment targets (incl. tuple/list unpacking, starred)."""
    if isinstance(t, ast.Name):
        return [t.id]
    if isinstance(t, (ast.Tuple, ast.List)):
        out = []
        for e in t.elts:
            out.extend(bind_names(e))
        return out
    if isinstance(t, ast.Starred):
        return bind_names(t.value)
    return []


def dotted(expr):
    """Syntactic dotted name of a Name/Attribute chain, else None."""
    parts = []
    while isinstance(expr, ast.Attribute):
        parts.append(expr.attr)
        expr = expr.value
    if isinstance(expr, ast.Name):
        parts.append(expr.id)
        return ".".join(reversed(parts))
    return None


class ModuleInfo:
    def __init__(self, rel, dotted_name, pkg):
        self.rel = rel                  # relpath (module id)
        self.dotted = dotted_name       # dotted name via pinned resolver
        self.pkg = pkg                  # package dotted prefix for relative imports
        self.parsed = False
        self.tree = None
        self.src = b""
        self.line_off = [0]
        self.bindings = {}              # name -> [record]; record: dict
        self.defs = {}                  # qual -> {kind, line, span, decorated_bad, cond}
        self.classes = {}               # qual -> class info
        self.star_import = False
        self.exec_taint = False
        self.module_getattr = False     # PEP 562

    def span(self, node):
        try:
            a = self.line_off[node.lineno - 1] + node.col_offset
            b = self.line_off[node.end_lineno - 1] + node.end_col_offset
            return (a, b)
        except Exception:
            return (0, 0)


class Extractor:
    def __init__(self, root, repo):
        self.root, self.repo = root, repo
        self.modules = {}               # rel -> ModuleInfo
        self.by_dotted = {}             # dotted -> rel
        self.edges = []
        self.subclass_overrides = {}    # (ancestor_qualid, member) -> True
        self.stats = {"attr_load_untracked": 0, "name_load_untracked": 0,
                      "value_escape_edges": 0}

    # ---------- pinned import resolver [P1] ----------
    def _discover(self):
        exclude_tests = os.environ.get("G0_EXCLUDE_TESTS") == "1"
        files = []
        for dirpath, dirnames, filenames in os.walk(self.root):
            dirnames[:] = sorted(d for d in dirnames if d != ".git")
            for fn in sorted(filenames):
                if fn.endswith(".py"):
                    rel = os.path.relpath(os.path.join(dirpath, fn), self.root)
                    if exclude_tests and _is_test_path(rel):
                        continue
                    files.append(rel)
        # pinned resolver roots: repo root, src/, plus every directory that
        # holds .py files but is NOT a package (no __init__.py) — models the
        # sys.path insertion pytest/scripts perform for bare sibling imports
        # (probe-detected resolver-scope fix [ASM-1058])
        nonpkg = set()
        for rel in files:
            d = os.path.dirname(rel)
            if d and not os.path.exists(os.path.join(self.root, d, "__init__.py")):
                nonpkg.add(d.replace(os.sep, "/"))
        roots = ["", "src"] + sorted(nonpkg)
        for rel in files:
            parts = rel.replace(os.sep, "/").split("/")
            dot = None
            for r in roots:
                rp = [p for p in r.split("/") if p]
                if parts[:len(rp)] == rp:
                    body = parts[len(rp):]
                    ok = True
                    # every intermediate dir must be a package (has __init__.py)
                    for i in range(1, len(body)):
                        d = os.path.join(self.root, *(rp + body[:i]))
                        if not os.path.exists(os.path.join(d, "__init__.py")):
                            ok = False
                            break
                    if not ok:
                        continue
                    mods = body[:-1] + ([] if body[-1] == "__init__.py"
                                        else [body[-1][:-3]])
                    dot = ".".join(mods) if mods else None
                    break
            pkg = None
            if dot is not None:
                pkg = dot if rel.endswith("__init__.py") else ".".join(dot.split(".")[:-1])
            mi = ModuleInfo(rel, dot, pkg or "")
            self.modules[rel] = mi
            if dot and dot not in self.by_dotted:
                self.by_dotted[dot] = rel

    def resolve_import(self, mi, target, level=0):
        """Resolve a dotted import target to a repo rel-path or ('ext', name)."""
        if level:
            base = mi.pkg.split(".") if mi.pkg else []
            base = base[:len(base) - (level - 1)] if level - 1 else base
            if level - 1 > 0 and not base:
                return ("ext", target)
            name = ".".join([p for p in base if p] + ([target] if target else []))
        else:
            name = target
        if not name:
            return ("ext", target or "?")
        if name in self.by_dotted:
            return ("repo", self.by_dotted[name])
        # import a.b -> binds a; but the edge target is a.b; try prefixes too
        return ("ext", name)

    # ---------- pass 1: parse, bindings, defs, classes, taints ----------
    def parse_all(self):
        self._discover()
        for rel, mi in self.modules.items():
            path = os.path.join(self.root, rel)
            try:
                mi.src = open(path, "rb").read()
                off, tot = [0], 0
                for line in mi.src.splitlines(keepends=True):
                    tot += len(line)
                    off.append(tot)
                mi.line_off = off
                mi.tree = ast.parse(mi.src, filename=rel)
                mi.parsed = True
            except (SyntaxError, ValueError):
                for rel_kind in ("call", "import", "binding", "instantiate"):
                    self.edges.append(Edge(rel_kind, rel, None, "unknown", "*",
                                           rel, (0, 0), "MODULE_UNPARSED"))
                continue
            self._collect(mi)

    def _collect(self, mi):
        def add_bind(name, rec):
            mi.bindings.setdefault(name, []).append(rec)

        def walk(body, stack, scope_kind, cond):
            for node in body:
                if isinstance(node, (ast.FunctionDef, ast.AsyncFunctionDef, ast.ClassDef)):
                    qual = ".".join(stack + [node.name]) if stack else node.name
                    kind = "class" if isinstance(node, ast.ClassDef) else "function"
                    decs = [dotted(d.func) if isinstance(d, ast.Call) else dotted(d)
                            for d in node.decorator_list]
                    bad_dec = any(d is None or d not in ALLOWLIST for d in decs)
                    mi.defs[qual] = {"kind": kind, "line": node.lineno,
                                     "span": mi.span(node), "decorated_bad": bad_dec,
                                     "cond": cond, "node": node}
                    if scope_kind in ("module", "class"):
                        add_bind(node.name, {"kind": kind, "qual": qual,
                                             "cond": cond or scope_kind == "class",
                                             "top": scope_kind == "module" and not cond,
                                             "bad_dec": bad_dec, "line": node.lineno,
                                             "span": mi.span(node)})
                    if kind == "class":
                        members = {}
                        for c in node.body:
                            if isinstance(c, (ast.FunctionDef, ast.AsyncFunctionDef)):
                                cdecs = [dotted(d.func) if isinstance(d, ast.Call) else dotted(d)
                                         for d in c.decorator_list]
                                members[c.name] = {
                                    "qual": qual + "." + c.name,
                                    "bad_dec": any(x is None or x not in ALLOWLIST
                                                   for x in cdecs)}
                        mi.classes[qual] = {
                            "bases": node.bases, "line": node.lineno,
                            "members": members,
                            "member_names": {c.name for c in node.body
                                             if isinstance(c, (ast.FunctionDef,
                                                               ast.AsyncFunctionDef,
                                                               ast.ClassDef))}
                                            | {t.id for c in node.body
                                               if isinstance(c, ast.Assign)
                                               for t in c.targets
                                               if isinstance(t, ast.Name)},
                            "kwds": bool(node.keywords),
                            "decorated": bool(node.decorator_list),
                            "multi": len(node.bases) > 1,
                            "hooks": bool({c.name for c in node.body
                                           if isinstance(c, (ast.FunctionDef,
                                                             ast.AsyncFunctionDef))}
                                          & ATTR_HOOKS)}
                        walk(node.body, stack + [node.name], "class", cond)
                    else:
                        if scope_kind == "module" and node.name == "__getattr__":
                            mi.module_getattr = True
                        walk(node.body, stack + [node.name], "function", cond)
                    continue
                if isinstance(node, (ast.Import, ast.ImportFrom)):
                    top = scope_kind == "module" and not cond
                    if isinstance(node, ast.Import):
                        for a in node.names:
                            res = self.resolve_import(mi, a.name)
                            bound = (a.asname or a.name.split(".")[0])
                            add_bind(bound, {"kind": "import", "target": res,
                                             "raw": a.name, "top": top,
                                             "cond": not top, "line": node.lineno,
                                             "span": mi.span(node),
                                             "sub": a.asname is None and "." in a.name})
                    else:
                        base = node.module or ""
                        for a in node.names:
                            if a.name == "*":
                                mi.star_import = True
                                res = self.resolve_import(mi, base, node.level)
                                self.edges.append(Edge("import", mi.rel,
                                                       None, "unknown",
                                                       res[1] if res[0] == "ext" else res[1],
                                                       mi.rel, mi.span(node), "IMPORT_STAR"))
                                continue
                            full = (base + "." + a.name) if base else a.name
                            res = self.resolve_import(mi, full, node.level)
                            if res[0] == "ext":
                                # member may be a symbol of a repo module
                                mres = self.resolve_import(mi, base, node.level)
                                res = ("member", mres, a.name)
                            add_bind(a.asname or a.name,
                                     {"kind": "from", "target": res, "raw": full,
                                      "top": top, "cond": not top,
                                      "line": node.lineno, "span": mi.span(node)})
                    # import EDGES emitted in pass 2 (need final resolver state)
                    walk_children(node, stack, scope_kind, cond)
                    continue
                if isinstance(node, (ast.Assign, ast.AnnAssign, ast.AugAssign)):
                    if scope_kind in ("module", "class"):
                        tgts = node.targets if isinstance(node, ast.Assign) else [node.target]
                        for t in tgts:
                            for nm in bind_names(t):
                                add_bind(nm, {"kind": "assign",
                                              "top": scope_kind == "module" and not cond,
                                              "cond": cond or scope_kind == "class",
                                              "scope": ".".join(stack),
                                              "line": node.lineno, "span": mi.span(node)})
                    walk_children(node, stack, scope_kind, cond)
                    continue
                if isinstance(node, ast.Global) and scope_kind == "function":
                    for nm in node.names:
                        add_bind(nm, {"kind": "assign", "top": False, "cond": True,
                                      "line": node.lineno, "span": mi.span(node)})
                    continue
                # compound statements -> conditional context
                walk_children(node, stack, scope_kind, cond=True
                              if isinstance(node, (ast.If, ast.Try, ast.While,
                                                   ast.For, ast.AsyncFor, ast.With,
                                                   ast.AsyncWith))
                              else cond)

        def walk_children(node, stack, scope_kind, cond):
            for fname, val in ast.iter_fields(node):
                if isinstance(val, list) and val:
                    if isinstance(val[0], ast.stmt):
                        walk(val, stack, scope_kind, cond)
                    elif isinstance(val[0], ast.excepthandler):
                        for h in val:
                            walk(h.body, stack, scope_kind, cond)

        walk(mi.tree.body, [], "module", False)
        # exec/eval/compile taint scan (over-approximate, fail-closed)
        for node in ast.walk(mi.tree):
            if isinstance(node, ast.Call) and isinstance(node.func, ast.Name) \
                    and node.func.id in EXEC_NAMES:
                mi.exec_taint = True
                break

    # ---------- module-level lookup helpers ----------
    def unique_top_binding(self, mi, name):
        recs = mi.bindings.get(name)
        if not recs or len(recs) != 1 or not recs[0].get("top"):
            return None
        return recs[0]

    def resolve_global_name(self, mi, name, depth=0):
        """Resolve module-scope name -> ('def'|'class', mi2, qual) |
        ('ext', dotted) | ('module', rel) | None (unknown)."""
        if depth > 4 or mi.star_import or mi.exec_taint:
            return None
        rec = self.unique_top_binding(mi, name)
        if rec is None:
            if name not in mi.bindings and name in BUILTIN_NAMES:
                return ("ext", "builtins." + name)
            return None
        if rec["kind"] in ("function", "class"):
            if rec.get("bad_dec"):
                return None
            return (rec["kind"], mi, rec["qual"])
        if rec["kind"] == "import":
            tgt = rec["target"]
            if rec.get("sub"):
                return None  # 'import a.b' binds a with submodule side effects
            if tgt[0] == "repo":
                return ("module", tgt[1])
            return ("extmodule", tgt[1])
        if rec["kind"] == "from":
            tgt = rec["target"]
            if tgt[0] == "repo":
                return ("module", tgt[1])  # from pkg import module_file
            if tgt[0] == "member":
                mres, member = tgt[1], tgt[2]
                if mres[0] == "repo":
                    mi2 = self.modules[mres[1]]
                    if not mi2.parsed:
                        return None
                    return self.resolve_member(mi2, member, depth + 1)
                return ("ext", mres[1] + "." + member)
            return ("ext", tgt[1])
        return None  # assign-bound or other

    def resolve_member(self, mi2, member, depth=0):
        if mi2.star_import or mi2.exec_taint or mi2.module_getattr:
            return None
        rec = self.unique_top_binding(mi2, member)
        if rec is None:
            return None
        if rec["kind"] in ("function", "class"):
            if rec.get("bad_dec"):
                return None
            return (rec["kind"], mi2, rec["qual"])
        return self.resolve_global_name(mi2, member, depth + 1)

    # ---------- class chain (single inheritance, fully analyzed) [P7/P8] ----------
    def class_chain(self, mi, qual, seen=None):
        """Return list of (mi, qual) ancestors incl. self, or None on hazard."""
        seen = seen or set()
        if (mi.rel, qual) in seen:
            return None
        seen.add((mi.rel, qual))
        ci = mi.classes.get(qual)
        if ci is None or ci["kwds"] or ci["decorated"] or ci["multi"] or ci["hooks"]:
            return None
        chain = [(mi, qual)]
        if not ci["bases"]:
            return chain
        base = ci["bases"][0]
        if isinstance(base, ast.Name) and base.id == "object":
            return chain
        d = dotted(base)
        if d is None:
            return None
        res = None
        if "." not in d:
            res = self.resolve_global_name(mi, d)
        else:
            head, tail = d.split(".", 1)
            g = self.resolve_global_name(mi, head)
            if g and g[0] == "module" and "." not in tail:
                mi2 = self.modules[g[1]]
                res = self.resolve_member(mi2, tail) if mi2.parsed else None
        if not res or res[0] != "class":
            return None
        rest = self.class_chain(res[1], res[2], seen)
        return None if rest is None else chain + rest

    def mro_lookup(self, mi, qual, member):
        """('ok', mi2, qual2) | None (hazard/unresolved)."""
        chain = self.class_chain(mi, qual)
        if chain is None:
            return None
        for cmi, cq in chain:
            ci = cmi.classes[cq]
            m = ci["members"].get(member)
            if m is not None:
                if m["bad_dec"]:
                    return None
                # repo-internal override check [ASM-1054]
                key = (cmi.rel + "::" + cq, member)
                if self.subclass_overrides.get(key):
                    return None
                return ("ok", cmi, m["qual"])
            if member in ci["member_names"]:
                return None  # bound to a non-def class attr -> untracked value
        return None  # not found in analyzed chain: could be instance attr

    def build_override_index(self):
        for rel, mi in self.modules.items():
            if not mi.parsed:
                continue
            for qual in mi.classes:
                chain = self.class_chain(mi, qual)
                if not chain or len(chain) < 2:
                    continue
                for member in mi.classes[qual]["member_names"]:
                    for ami, aq in chain[1:]:
                        self.subclass_overrides[(ami.rel + "::" + aq, member)] = True

    # ---------- pass 2: emit edges ----------
    def extract(self):
        self.parse_all()
        self.build_override_index()
        for rel, mi in sorted(self.modules.items()):
            if mi.parsed:
                self._emit_module(mi)
        return self.edges

    def _emit_module(self, mi):
        E = self.edges
        rel = mi.rel
        if mi.exec_taint:
            for rk in ("call", "import", "binding", "instantiate"):
                E.append(Edge(rk, rel, None, "unknown", "*", rel, (0, 0), "TAINT_EXEC"))

        # ---- import edges + binding facts ----
        def ancestors(target_rel):
            """Repo __init__.py files of every ancestor package: importing
            a.b.c also imports a and a.b (parent-package closure — Python
            import semantics; probe-detected validity fix)."""
            out = []
            parts = target_rel.replace(os.sep, "/").split("/")
            for i in range(1, len(parts)):
                cand = "/".join(parts[:i]) + "/__init__.py"
                if cand in self.modules and cand != target_rel:
                    out.append(cand)
            return out

        for name, recs in mi.bindings.items():
            for r in recs:
                if r["kind"] in ("import", "from"):
                    tgt = r["target"]
                    if tgt[0] == "member":
                        repo_rel = tgt[1][1] if tgt[1][0] == "repo" else None
                    else:
                        repo_rel = tgt[1] if tgt[0] == "repo" else None
                    if repo_rel is not None:
                        dst, cand = "repo:" + repo_rel, repo_rel
                        closure = [repo_rel] + ancestors(repo_rel)
                    else:
                        extname = tgt[1][1] if tgt[0] == "member" else tgt[1]
                        dst, cand = "ext:" + extname, extname
                        closure = []
                    if r.get("top"):
                        E.append(Edge("import", rel, dst, "proved", None, rel,
                                      r["span"], "P1"))
                        for anc in (closure[1:] if closure else []):
                            E.append(Edge("import", rel, "repo:" + anc,
                                          "proved", None, rel, r["span"], "P1"))
                    else:
                        E.append(Edge("import", rel, dst, "unknown", str(cand),
                                      rel, r["span"], "IMPORT_CONDITIONAL"))
                        for anc in (closure[1:] if closure else []):
                            E.append(Edge("import", rel, None, "unknown", anc,
                                          rel, r["span"], "IMPORT_CONDITIONAL"))
                elif r["kind"] in ("function", "class", "assign"):
                    pass  # binding facts emitted from defs/assign walk below

        # binding facts: defs at any nesting (syntactic sites)
        for qual, d in mi.defs.items():
            E.append(Edge("binding", rel, rel + "::" + qual, "proved", None, rel,
                          d["span"], "P3"))
            # containment (lexical)
            parent = rel if "." not in qual else rel + "::" + qual.rsplit(".", 1)[0]
            E.append(Edge("contains", parent, rel + "::" + qual, "proved", None,
                          rel, d["span"], "P2"))
        for name, recs in mi.bindings.items():
            for r in recs:
                if r["kind"] == "assign":
                    scope = r.get("scope", "")
                    dst = rel + "::" + (scope + "." + name if scope else name)
                    E.append(Edge("binding", rel, dst, "proved",
                                  None, rel, r["span"], "P3"))
                    parent = rel + "::" + scope if scope else rel
                    E.append(Edge("contains", parent, dst, "proved", None,
                                  rel, r["span"], "P2"))

#!/usr/bin/env python3
"""CODEVERT G0 — dynamic trace probe (G1 §7 soundness-probe mini, mechanical).

Runs a repo's own test suite under sys.setprofile + a builtins.__import__
wrapper, recording (a) intra-repo Python call edges (caller frame -> callee
frame, both files under the repo root) and (b) import events attributed to
the importing repo file. NO annotation; extractor-independent observations.

Usage: probe_runner.py <repo_root> <test_path> <out_json>
"""
import builtins, json, os, sys


def main():
    repo_root = os.path.abspath(sys.argv[1])
    test_path = sys.argv[2]
    out_json = sys.argv[3]
    prefix = repo_root + os.sep
    call_edges = set()
    import_events = set()

    GEN_FLAGS = 0x20 | 0x80 | 0x200  # GENERATOR | COROUTINE | ASYNC_GENERATOR

    def prof(frame, event, arg):
        if event != "call":
            return
        co = frame.f_code
        fn = co.co_filename
        if not fn.startswith(prefix):
            return
        back = frame.f_back
        if back is None:
            return
        bco = back.f_code
        bfn = bco.co_filename
        if not bfn.startswith(prefix):
            return
        call_edges.add((bfn[len(prefix):], bco.co_name, bco.co_firstlineno,
                        fn[len(prefix):], co.co_name, co.co_firstlineno,
                        bool(co.co_flags & GEN_FLAGS)))

    orig_import = builtins.__import__

    def imp(name, globals=None, locals=None, fromlist=(), level=0):
        try:
            f = sys._getframe(1)
            fn = f.f_code.co_filename
            if fn.startswith(prefix):
                pkg = (globals or {}).get("__package__") or ""
                import_events.add((fn[len(prefix):], name, level, str(pkg),
                                   tuple(fromlist or ())))
        except Exception:
            pass
        return orig_import(name, globals, locals, fromlist, level)

    sys.path.insert(0, repo_root)
    if os.path.isdir(os.path.join(repo_root, "src")):
        sys.path.insert(0, os.path.join(repo_root, "src"))
    os.chdir(repo_root)

    builtins.__import__ = imp
    sys.setprofile(prof)
    import pytest
    rc = pytest.main([test_path, "-q", "-x" if False else "--continue-on-collection-errors",
                      "-p", "no:cacheprovider"])
    sys.setprofile(None)
    builtins.__import__ = orig_import

    with open(out_json, "w") as fh:
        json.dump({"repo_root": repo_root, "pytest_exit": int(rc),
                   "n_call_edges": len(call_edges),
                   "n_import_events": len(import_events),
                   "call_edges": sorted(call_edges),
                   "import_events": sorted(import_events)}, fh)
    print("edges:", len(call_edges), "imports:", len(import_events), "rc:", rc)


if __name__ == "__main__":
    main()
#!/usr/bin/env python3
"""CODEVERT G0 — dynamic-probe soundness/validity checker (mechanical).

Spec basis: CODEVERT §7-G1 endpoint 5 [PROPOSED-ASM: ASM-1030] run here as a
NON-SCORED mini-probe: every OBSERVED intra-repo call/import edge must appear
in proved ∪ unknown-compatible; an observed edge absent from both is an
extractor SOUNDNESS miss. Additionally checks proved (completeness-claiming)
answers against observations: an observed importer absent from a
proved imported-by listing, or an observed caller absent from a proved
callers-of listing, is a NEGATIVE-ANSWER VALIDITY violation.

Generator/coroutine frame activations are classified separately (a resumption
is not a call statement; disclosed, not hidden).
"""
import bisect, json, os, sys

sys.setrecursionlimit(100000)
from extractor import Extractor
from engine import World


def line_of(mi, byte_off):
    return bisect.bisect_right(mi.line_off, byte_off)


def main(repo, probe_json, out_json):
    base = os.path.dirname(os.path.abspath(__file__))
    root = os.path.join(base, "corpus", repo)
    ex = Extractor(root, repo)
    edges = ex.extract()
    world = World(edges, ex.modules)

    # --- indexes ---
    proved_pairs = set()
    inst_by_src = {}
    unk_by_src = {}      # src -> set of cands
    taint_mods = set()
    for e in edges:
        if e.status == "proved" and e.rel in ("call", "instantiate"):
            proved_pairs.add((e.src, e.dst))
            if e.rel == "instantiate":
                inst_by_src.setdefault(e.src, set()).add(e.dst)
        elif e.status == "unknown":
            if e.rel in ("call", "instantiate"):
                unk_by_src.setdefault(e.src, set()).add(e.cand)
            if e.reason in ("TAINT_EXEC", "MODULE_UNPARSED"):
                taint_mods.add(e.src)

    defidx = {}          # (rel, name) -> [(line, qual, kind)]
    ranges = {}          # rel -> [(start_line, end_line, qual)]
    for rel, mi in ex.modules.items():
        if not mi.parsed:
            continue
        rr = []
        for qual, d in mi.defs.items():
            nm = qual.split(".")[-1]
            defidx.setdefault((rel, nm), []).append((d["line"], qual, d["kind"]))
            rr.append((line_of(mi, d["span"][0]), line_of(mi, d["span"][1] - 1), qual))
        ranges[rel] = sorted(rr)

    def map_def(rel, name, firstlineno):
        cands = defidx.get((rel, name), [])
        best = None
        for line, qual, kind in cands:
            diff = line - firstlineno
            if -2 <= diff <= 20 and (best is None or abs(diff) < abs(best[0])):
                best = (diff, qual, kind)
        if best:
            return best[1], best[2]
        if len(cands) == 1:
            return cands[0][1], cands[0][2]
        return None

    def innermost(rel, lineno):
        best = None
        for a, b, qual in ranges.get(rel, []):
            if a <= lineno <= b and (best is None or (b - a) < best[0]):
                best = (b - a, qual)
        return rel + "::" + best[1] if best else rel

    def map_caller(rel, name, firstlineno):
        if name == "<module>":
            return rel
        if name.startswith("<"):
            return innermost(rel, firstlineno)
        m = map_def(rel, name, firstlineno)
        return rel + "::" + m[0] if m else innermost(rel, firstlineno)

    def chain_ids(file, qual):
        mi = ex.modules.get(file)
        ch = ex.class_chain(mi, qual) if mi and mi.parsed else None
        return {cmi.rel + "::" + cq for cmi, cq in ch} if ch else {file + "::" + qual}

    probe = json.load(open(probe_json))
    stats = {"confirmed_proved": 0, "confirmed_instantiation": 0,
             "unknown_compatible": 0, "miss": 0, "protocol_dispatch": 0,
             "descriptor_or_decorated": 0,
             "class_body_exec": 0, "unmapped_callee": 0,
             "resumption_total": 0, "resumption_unmatched": 0}
    qstats = {"covered": 0, "violation": 0}
    misses = []
    validity_viol = []

    for (cf, cn, cl, ef, en, el, is_gen) in probe["call_edges"]:
        if cf not in ex.modules or ef not in ex.modules:
            continue
        m = map_def(ef, en, el)
        if en.startswith("<") or m is None:
            if en in ("__init__", "__new__") or en.startswith("<"):
                stats["unmapped_callee"] += 1
                continue
            stats["unmapped_callee"] += 1
            continue
        equal, kind = m
        if kind == "class":
            stats["class_body_exec"] += 1
            continue
        src = map_caller(cf, cn, cl)
        dst = ef + "::" + equal
        name = equal.split(".")[-1]

        def matches():
            if (src, dst) in proved_pairs:
                return "confirmed_proved"
            # instantiation: observed __init__/__new__ of class K, proved
            # instantiate edge src -> C with K in C's analyzed chain
            if name in ("__init__", "__new__") and "." in equal:
                kq = equal.rsplit(".", 1)[0]
                kid = ef + "::" + kq
                for c in inst_by_src.get(src, ()):
                    parts = c.split("::")
                    if c == kid or (len(parts) == 2
                                    and kid in chain_ids(parts[0], parts[1])):
                        return "confirmed_instantiation"
            cands = unk_by_src.get(src, set())
            if "*" in cands or name in cands:
                return "unknown_compatible"
            # a call site naming the CLASS is the candidate for its __init__
            if name in ("__init__", "__new__") and "." in equal \
                    and equal.rsplit(".", 1)[0].split(".")[-1] in cands:
                return "unknown_compatible"
            if cf in taint_mods or (src.split("::")[0] in taint_mods):
                return "unknown_compatible"
            # implicit language-protocol dispatch (x[k], with, ==, descriptor
            # ...) has NO syntactic call site: outside the call relation's
            # domain as spec'd; classified separately, disclosed [ASM-1057]
            if name.startswith("__") and name.endswith("__") \
                    and name not in ("__init__", "__new__", "__call__"):
                return "protocol_dispatch"
            # property/descriptor invocation: attribute ACCESS runs the def
            # (no syntactic call site); decorated defs classified separately
            d = ex.modules[ef].defs.get(equal)
            if d and d.get("decorated_bad"):
                return "descriptor_or_decorated"
            return "miss"

        r = matches()
        # ---- QUERY-LEVEL soundness (the ASM-1030-relevant criterion):
        # the observed edge is a query violation ONLY if the corresponding
        # inverse query answers `proved` while missing it (fail-closed
        # blocking otherwise protects the answer)
        if not is_gen:
            if name in ("__init__", "__new__") and "." in equal:
                kq = equal.rsplit(".", 1)[0]
                stq, _, _ = world.instance_of(ef, kq)
                ok = stq != "proved" or any(
                    c == ef + "::" + kq for c in inst_by_src.get(src, ()))
            else:
                stq, listing, _ = world.callers_of(ef, equal)
                ok = stq != "proved" or src in listing
            if ok:
                qstats["covered"] += 1
            else:
                qstats["violation"] += 1
                validity_viol.append({"family": "call", "target": dst,
                                      "observed_src": src})
        if is_gen:
            stats["resumption_total"] += 1
            if r == "miss":
                stats["resumption_unmatched"] += 1
            else:
                stats[r] += 1
            continue
        stats[r] += 1
        if r == "miss" and len(misses) < 40:
            misses.append({"caller": src, "callee": dst,
                           "caller_frame": [cf, cn, cl], "callee_line": el})

    # --- imports ---
    istats = {"confirmed": 0, "unknown_compatible": 0, "miss": 0, "external": 0}
    imisses = []
    observed_importers = {}   # repo module rel -> set of importer rels
    for (rel, name, level, pkg, fromlist) in probe["import_events"]:
        if rel not in ex.modules or not ex.modules[rel].parsed:
            continue
        mi = ex.modules[rel]
        targets = []
        r0 = ex.resolve_import(mi, name, level)
        if r0[0] == "repo":
            targets.append(r0[1])
        for fm in fromlist:
            if fm == "*":
                continue
            rf = ex.resolve_import(mi, (name + "." + fm) if name else fm, level)
            if rf[0] == "repo":
                targets.append(rf[1])
        if not targets:
            istats["external"] += 1
            continue
        unk_imp = {e.cand for e in world.unk_import_by_src.get(rel, ())}
        for t in targets:
            observed_importers.setdefault(t, set()).add(rel)
            tmi = ex.modules.get(t)
            names = {t} | ({tmi.dotted} if tmi and tmi.dotted else set())
            if any(e.dst == "repo:" + t
                   for e in world.proved_import_by_src.get(rel, ())):
                istats["confirmed"] += 1
            elif "*" in unk_imp or (names & unk_imp) or rel in taint_mods:
                istats["unknown_compatible"] += 1
            else:
                istats["miss"] += 1
                if len(imisses) < 20:
                    imisses.append({"importer": rel, "target": t,
                                    "stmt": [name, level, list(fromlist)]})

    # imported-by completeness validity on proved answers
    for t, importers in observed_importers.items():
        st, listing, _ = world.imported_by(t)
        if st == "proved":
            for i in importers - set(listing):
                validity_viol.append({"family": "imported_by", "target": t,
                                      "observed_src": i})

    out = {"repo": repo, "pytest_exit": probe["pytest_exit"],
           "n_observed_call_edges": len(probe["call_edges"]),
           "n_observed_import_events": len(probe["import_events"]),
           "call_soundness": stats, "call_query_level": qstats,
           "call_miss_examples": misses,
           "import_soundness": istats, "import_miss_examples": imisses,
           "validity_violations": validity_viol,
           "n_validity_violations": len(validity_viol)}
    with open(out_json, "w") as fh:
        json.dump(out, fh, indent=1)
    print(json.dumps({k: out[k] for k in ("repo", "pytest_exit",
                                          "call_soundness", "call_query_level",
                                          "import_soundness",
                                          "n_validity_violations")}, indent=1))


if __name__ == "__main__":
    main(sys.argv[1], sys.argv[2], sys.argv[3])

