/bin/bash -lc "PYTHONDONTWRITEBYTECODE=1 python3 - <<'PY'
import os,sys,json
B='poc/codevert-g0';sys.path.insert(0,B)
from extractor import Extractor
c=json.load(open(B+'/results/census.json'))['repos']; saved=json.load(open(B+'/results/g0-ablation-unrestricted.json'))
for repo,cd in c.items():
 ex=Extractor(B+'/corpus/'+repo,repo); w=__import__('engine').World(ex.extract(),ex.modules)
 out={}
 for fam in ('callers_of','imported_by','where_defined','instance_of'):
  ok=0;u=cd['universes'][fam]
  for t in u:
   if fam=='callers_of':
    mi=w.modules.get(t['file']); found=mi and mi.parsed and t['qual'] in mi.defs
    n=t['qual'].split('.')[-1]; blocked=w.unk_call_cand.get(n,0)+w.n_unparsed
   elif fam=='instance_of':
    mi=w.modules.get(t['file']); found=mi and mi.parsed and t['qual'] in mi.defs
    n=t['qual'].split('.')[-1]; blocked=w.unk_call_cand.get(n,0)+w.unk_inst_cand.get(n,0)+w.n_unparsed
   elif fam=='where_defined':
    found=True;n=t['name'];blocked=w.unk_bind_cand.get(n,0)+w.n_unparsed
   else:
    mi=w.modules.get(t['file']);found=mi and mi.parsed
    names={t['file']}|({mi.dotted} if mi and mi.dotted else set());blocked=sum(w.unk_import_cand.get(n,0) for n in names)+w.n_unparsed
   ok += bool(found and not blocked)
  out[fam]=round(ok/len(u),4)
 print(repo,out,'saved',saved[repo]['ablated'])
PY"

